const callback = $json.callback_query;

if (!callback) {
  console.log('⚠️ Set Context: Not a callback - skipping');
  return { json: $json };
}

const userId = callback.from.id || callback.message.chat.id;
const choice = callback.data;

console.log(`Set Context - userId: ${userId}, choice: ${choice}`);

const tableMap = {
  "Психология ИИ": "tbloVFbVCQ5rxt5K8",
  "Выпуски журнала «Ч»": "tbljFieoM9nqNqhb6"
};

if (!staticData.userTables) {
  staticData.userTables = {};
}

let resolvedTable = tableMap[choice];

