  resolvedTable = "tbloVFbVCQ5rxt5K8";
  console.log(`✅ Detected nested psy: button, using Психология ИИ table`);
}

if (resolvedTable) {
  staticData.userTables[userId] = resolvedTable;
  console.log(`✅ Saved tableId: ${resolvedTable} for user: ${userId}`);
} else {
  console.log(`⚠️ Unknown choice: ${choice}`);
}

return {
  json: {
    ...$json,
