// Get Context - unified retrieval, с отладкой и fallback'ами
const staticData = $getWorkflowStaticData('global');
const callback = $json.callback_query;
const message = $json.message || {};

// Вычисляем тот же userId по тем же правилам (симметрия с Set Context)
const userId = message?.from?.id || message?.chat?.id || callback?.from?.id || callback?.message?.chat?.id;

console.log(`Get Context - userId: ${userId}`);
console.log("Get Context - staticData.userTables:", JSON.stringify(staticData.userTables));

// Безопасные проверки
if (!staticData.userTables || typeof staticData.userTables !== 'object') {
  staticData.userTables = {};
}

const tableId = staticData.userTables[userId] ?? null;

console.log(`Get Context - Retrieved tableId: ${tableId}`);

if (!tableId) {
  // Возвращаем полезную отладочную структуру, чтобы дальше было видно, почему fail
  return {
    json: {
      error: "No table selected",
      chatId: message?.chat?.id || callback?.message?.chat?.id || null,
      debugInfo: {
        userId: userId,
        hasUserTables: !!Object.keys(staticData.userTables).length,
        allTables: staticData.userTables
      }
    }
  };
}

// Успешный путь: добавляем tableId в payload
return {
  json: {
    ...$json,
    tableId: tableId
  }
};

