const records = $input.all();
const contextData = $('Get Context').first().json;
const userQuery = contextData.message.text;
const chatId = contextData.message.chat.id;
const tableId = contextData.tableId;

const tableNames = {
  "tbloVFbVCQ5rxt5K8": "Психология ИИ",
  "tbljFieoM9nqNqhb6": "Выпуски журнала «Ч»"
};

const tableName = tableNames[tableId] || "Неизвестная таблица";

let formattedData;
let recordsToProcess;

if (tableId === "tbloVFbVCQ5rxt5K8") {
  // ========== ТАБЛИЦА "ПСИХОЛОГИЯ ИИ" ==========

  // 🔥 ОПТИМИЗАЦИЯ: Уменьшили с 1500 до 600.
  // Этого достаточно для понимания сути, но снижает нагрузку в 2.5 раза.
  const MAX_TEXT_LENGTH = 600; 

  // === УМНАЯ СОРТИРОВКА (Оставляем как есть, она полезная) ===
  const stopWords = ['что', 'есть', 'про', 'где', 'когда', 'как', 'это', 'все', 'или', 'дай', 'покажи', 'найди'];

  const queryWords = userQuery
    .toLowerCase()
    .split(/\s+/)
    .filter(w => w.length > 2 && !stopWords.includes(w));

  function calculateRelevance(record, words) {
    const fields = {
      'Название': (record['Название'] || '').toLowerCase(),
      'Summary': (record['Summary'] || '').toLowerCase(),
      'ТекстПоста': (record['Текст исходного поста'] || '').toLowerCase(),
      'ТекстФайла': (record['Текст из файла'] || '').toLowerCase(),
      'Комментарий': (record['Комммментарий отправитель'] || '').toLowerCase(),
      'Теги': (record['Теги'] || []).join(' ').toLowerCase()
    };

    let score = 0;
    words.forEach(word => {
      if (fields['Название'] === word) score += 20;
      else if (fields['Название'].includes(word)) score += 10;
      if (fields['Summary'].includes(word)) score += 5;
      if (fields['Теги'].includes(word)) score += 3;
      if (fields['Комментарий'].includes(word)) score += 2;
      if (fields['ТекстПоста'].includes(word)) score += 1;
      if (fields['ТекстФайла'].includes(word)) score += 1;
    });
    return score;
  }

  const sortedRecords = records.sort((a, b) => {
    const scoreA = calculateRelevance(a.json, queryWords);
    const scoreB = calculateRelevance(b.json, queryWords);
    return scoreB - scoreA;
  });

  // 🔥 ОПТИМИЗАЦИЯ: Берем топ-25 вместо топ-50
  // Если модель перегружена, лучше дать 25 самых релевантных, чем упасть с ошибкой.
  recordsToProcess = Math.min(25, sortedRecords.length);

  console.log(`📊 Обрабатываем ${recordsToProcess} записей (Optimized)`);

  formattedData = sortedRecords.slice(0, recordsToProcess).map((item, index) => {
    const record = item.json;

    let entry = `┌──── ЗАПИСЬ #${index + 1} ────┐\n`;
    entry += `📌 Название: ${record['Название'] || 'Без названия'}\n`;

    if (record['Автор поста']) entry += `👤 Автор: ${record['Автор поста']}\n`;
    if (record['Summary']) entry += `📝 Краткое описание: ${record['Summary']}\n`;

    let fullText = record['Текст исходного поста'] || record['Текст из файла'] || '';

    if (fullText) {
      // Умная обрезка: берем начало текста
      const textPreview = fullText.length > MAX_TEXT_LENGTH 
        ? fullText.substring(0, MAX_TEXT_LENGTH) + '...\n[текст сокращён]' 
        : fullText;
      entry += `\n📄 ТЕКСТ:\n${textPreview}\n`;
    }

    if (record['Комммментарий отправитель']) entry += `\n💬 Комментарий: ${record['Комммментарий отправитель']}\n`;
    if (record['Теги'] && record['Теги'].length > 0) entry += `🏷️ Теги: ${record['Теги'].join(', ')}\n`;
    if (record['Источник']) entry += `🔗 Источник: ${record['Источник']}\n`;

    return entry;
  }).join('\n\n');

} else if (tableId === "tbljFieoM9nqNqhb6") {
  // ========== ТАБЛИЦА "ВЫПУСКИ ЖУРНАЛА" ==========

  // 🔥 ОПТИМИЗАЦИЯ: Уменьшили с 3000 до 1000.
  const MAX_TEXT_PER_ISSUE = 1000;
  // 🔥 ОПТИМИЗАЦИЯ: Берем 5 последних выпусков вместо 10 (обычно актуальны свежие)
  const MAX_ISSUES = 5;

  recordsToProcess = Math.min(MAX_ISSUES, records.length);
  console.log(`📊 Выпуски журнала: обрабатываем ${recordsToProcess} записей (Optimized)`);

  formattedData = records.slice(0, recordsToProcess).map((item, index) => {
    const record = item.json;

    let entry = `\n─────────────────────────────\n`;
    entry += `📰 ВЫПУСК #${index + 1}: ${record['Название'] || 'Без названия'}\n`;
    entry += `─────────────────────────────\n`;

    if (record['Дата выхода']) entry += `📅 Дата: ${record['Дата выхода']}\n`;
    if (record['Тэги']) entry += `🏷️ Теги: ${record['Тэги'].join(', ')}\n`;
    if (record['Источник']) entry += `🔗 Источник: ${record['Источник']}\n`;

    if (record['Исходный текст']) {
      const fullText = record['Исходный текст'];
      const textPreview = fullText.length > MAX_TEXT_PER_ISSUE 
        ? fullText.substring(0, MAX_TEXT_PER_ISSUE) + '...\n[текст сокращен]' 
        : fullText;

      entry += `\n📄 ТЕКСТ ВЫПУСКА:\n${textPreview}\n`;
    }

    return entry;
  }).join('\n\n');
}

return {
  json: {
    promptContext: formattedData,
    userQuery: userQuery,
    chatId: chatId,
    totalRecords: records.length,
    recordsProcessed: recordsToProcess,
    tableName: tableName,
    tableId: tableId
  }
};

const output = $json.output || '';

if ($json.error || !output || output.trim() === '') {
  return { json: { hasError: true, errorMessage: $json.error || 'AI не вернул ответ', chatId: $('Format Data for AI').item.json.chatId } };
}



// 1. Очистка
let cleanOutput = output
  .replace(/- ИСПОЛЬЗУЙ ЭТО НАЗВАНИЕ ИЗ TELEGRAM/gi, '')
  .replace(/ИСПОЛЬЗУЙ ЭТО НАЗВАНИЕ ИЗ TELEGRAM/gi, '')
  .replace(/\(ИСПОЛЬЗУЙ[^)]*\)/gi, '')
  .replace(/\[\.\.\.конец фрагмента\]/gi, '')
  // Убираем ромбы и прочие эмодзи (кроме тех, что мы сами добавим)
  .replace(/[\u{1F300}-\u{1F9FF}]/gu, '') 
  .replace(/🔷/g, '')
  .trim();

// 2. ВОССТАНОВЛЕНИЕ ССЫЛОК
// Вариант А: Идеальный Markdown [Текст](URL) -> <a href="URL">Текст</a>
cleanOutput = cleanOutput.replace(/\[([^\]]+?)\]\((https?:\/\/[^\s)]+)\)/g, '<a href="$2">$1</a>');

// Вариант Б: Просто URL в тексте -> 🔗 Источник
// Но чтобы не дублировать, если ссылка уже внутри тега <a>, используем хитрую проверку.
// (Проще всего: сначала обработать MD, а потом оставшиеся "голые" ссылки превратить в "Источник")
cleanOutput = cleanOutput.replace(/(^|\s)(https?:\/\/[^\s<]+)/g, '$1<a href="$2">🔗 Источник</a>');


// 3. ФОРМАТИРОВАНИЕ ЗАГОЛОВКОВ
// Markdown ###
cleanOutput = cleanOutput.replace(/(^|\n)(#{2,})\s*(.+?)(\n|$)/g, '\n\n<b>$3</b>\n');

// 4. ЖИРНЫЙ и СПИСКИ
cleanOutput = cleanOutput.replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');
cleanOutput = cleanOutput.replace(/(^|\n)\s*[\-\*•]\s+/g, '\n• ');

// 5. ОТСТУПЫ
cleanOutput = cleanOutput.replace(/([^\n])\n([^\n•])/g, '$1\n\n$2');
cleanOutput = cleanOutput.replace(/\n{3,}/g, '\n\n');

return { json: { output: cleanOutput, hasError: false } };

// 6. ВАЛИДАЦИЯ ТЕГОВ
function balanceTags(html) {
  const tags = ['b', 'i', 'a'];
  tags.forEach(tag => {
      const open = (html.match(new RegExp(`<${tag}[^>]*>`, 'gi')) || []).length;
      const close = (html.match(new RegExp(`</${tag}>`, 'gi')) || []).length;
      if (open > close) {
          for(let i=0; i < (open - close); i++) html += `</${tag}>`;
      }
  });
  return html;
}

cleanOutput = balanceTags(cleanOutput);

return { json: { output: cleanOutput, hasError: false } };

